example.code:
# Good - Python 3.12+ native syntax (PREFERRED)
class DataTool[T]:
    """Generic I/O tool for any item type."""
    def __init__(self, parser: Parser[T], producer: Producer[T]) -> None:
        self.parser = parser
        self.producer = producer

    def process(self, input_text: str) -> T:
        items: T = self.parser.parse(input_text)  # Type preserved
        return items

class Stack[T]:
    """Generic stack with automatic variance inference."""
    def __init__(self) -> None:
        self._items: list[T] = []

    def push(self, item: T) -> None:
        self._items.append(item)

    def pop(self) -> T:
        return self._items.pop()

# Bad - loses type information
class DataTool:
    def __init__(self, parser, producer):
        self.parser = parser
        self.producer = producer
